-- ITINERA v0.16 · Carga inicial de datos locales en Supabase
-- Ejecutar después del schema v0.15/v0.15.1. Es idempotente: usa upsert/on conflict.

on conflict (id) do update set title=excluded.title,url=excluded.url,category=excluded.category,usefulness=excluded.usefulness,official=excluded.official,jurisdiction=excluded.jurisdiction,updated_at=now();

on conflict (id) do update set name=excluded.name,type=excluded.type,level=excluded.level,family=excluded.family,branch=excluded.branch,route=excluded.route,regulated=excluded.regulated,demand=excluded.demand,labour=excluded.labour,subjects=excluded.subjects,ponderation_subjects=excluded.ponderation_subjects,route_options=excluded.route_options,availability_by_province=excluded.availability_by_province,sources=excluded.sources,source_url=excluded.source_url,source_id=excluded.source_id,raw=excluded.raw,data_quality=excluded.data_quality,verified_at=excluded.verified_at,last_seen_at=now(),updated_at=now();

on conflict (study_id, normalized_alias) do update set alias=excluded.alias, alias_type=excluded.alias_type;

on conflict (id) do update set category=excluded.category,question=excluded.question,answer=excluded.answer,sources=excluded.sources,priority=excluded.priority,updated_at=now();

on conflict (id) do update set title=excluded.title,short=excluded.short,when_needed=excluded.when_needed,age=excluded.age,structure=excluded.structure,notes=excluded.notes,sources=excluded.sources,updated_at=now();

on conflict (id) do update set title=excluded.title,summary=excluded.summary,period=excluded.period,sources=excluded.sources,updated_at=now();

on conflict (id) do update set title=excluded.title,summary=excluded.summary,sources=excluded.sources,updated_at=now();

on conflict (id) do update set title=excluded.title,summary=excluded.summary,details=excluded.details,sources=excluded.sources,updated_at=now();

select
  (select count(*) from public.itinera_studies) as studies,
  (select count(*) from public.itinera_study_aliases) as aliases,
  (select count(*) from public.itinera_sources) as sources,
  (select count(*) from public.itinera_faq_items) as faq;