insert into public.itinera_faq_items(id,category,question,answer,sources,priority) values
('faq-qu-puedo-hacer-despus-de-la-eso-con-ttulo','Orientación general','¿Qué puedo hacer después de la ESO con título?','Puedes acceder a Bachillerato, FP de grado medio, enseñanzas artísticas de grado medio, enseñanzas deportivas de grado medio u otras vías según requisitos.','["educagob-eso", "todofp"]'::jsonb,1),
('faq-qu-pasa-si-no-tengo-el-ttulo-de-eso','Orientación general','¿Qué pasa si no tengo el título de ESO?','Debes revisar vías como FP básica, educación de personas adultas, pruebas de acceso u otras opciones. Depende de edad, requisitos y convocatoria.','["educagob-eso", "xunta-fp-oferta"]'::jsonb,2),
('faq-cmo-elijo-bachillerato-si-quiero-universidad','Orientación general','¿Cómo elijo Bachillerato si quiero universidad?','Parte del grado objetivo, consulta ponderaciones oficiales y revisa qué materias de segundo de Bachillerato te permiten competir mejor.','["educagob-bach-organizacion", "ciug-ponderaciones-2026"]'::jsonb,3),
('faq-qu-son-las-ponderaciones','Orientación general','¿Qué son las ponderaciones?','Son coeficientes que pueden sumar nota de admisión con materias concretas. En Galicia se consultan en la CIUG por grado y curso de acceso.','["ciug-ponderaciones-2026", "ciug-admision"]'::jsonb,4),
('faq-dnde-veo-notas-de-corte-en-galicia','Orientación general','¿Dónde veo notas de corte en Galicia?','La fuente que debe consultarse para admisión al Sistema Universitario de Galicia es la CIUG. Las notas cambian cada curso.','["ciug-admision"]'::jsonb,5),
('faq-cmo-s-si-un-ttulo-universitario-es-oficial','Orientación general','¿Cómo sé si un título universitario es oficial?','El RUCT es el registro oficial para comprobar universidades, centros y títulos oficiales.','["ruct"]'::jsonb,6),
('faq-derecho-requiere-mster','Orientación general','¿Derecho requiere máster?','El grado en Derecho por sí solo no habilita para ejercer abogacía/procura. Para esa vía se requiere formación habilitante posterior según normativa vigente.','["ruct-faq", "rd-822-2021"]'::jsonb,7),
('faq-psicologa-requiere-mster','Orientación general','¿Psicología requiere máster?','Para ejercer como Psicólogo/a General Sanitario/a se requiere el Máster Universitario en Psicología General Sanitaria. Otras salidas tienen requisitos distintos.','["ruct-faq", "rd-822-2021"]'::jsonb,8),
('faq-arquitectura-requiere-mster','Orientación general','¿Arquitectura requiere máster?','La vía profesional de arquitecto/a exige completar la formación habilitante correspondiente, habitualmente grado más Máster Universitario en Arquitectura.','["ruct-faq", "rd-822-2021"]'::jsonb,9),
('faq-qu-hago-si-quiero-psicologa-pero-se-me-dan-mal-las-matemticas','Orientación general','¿Qué hago si quiero Psicología pero se me dan mal las matemáticas?','No conviene decidir solo por ponderación. Revisa qué materias ponderan, estima tu nota realista, considera Biología u otras materias si ponderan y compara el riesgo de escoger una materia que te penalice. La decisión debe equilibrar ponderación y rendimiento probable.','["ciug-ponderaciones-2026", "ciug-admision"]'::jsonb,10),
('faq-dnde-consulto-fp-en-galicia','Orientación general','¿Dónde consulto FP en Galicia?','La oferta real de FP en Galicia debe comprobarse en la web oficial de FP de la Xunta, por curso, centro, régimen, familia y localidad.','["xunta-fp-oferta", "xunta-fp-centros", "xunta-fp-ciclos"]'::jsonb,11),
('faq-puedo-ir-de-fp-superior-a-universidad','Orientación general','¿Puedo ir de FP superior a universidad?','Sí, la FP de grado superior puede ser vía de acceso a universidad. Deben revisarse admisión, nota, plazas y si conviene mejorar nota con materias ponderables.','["todofp", "ciug-admision"]'::jsonb,12),
('faq-qu-becas-oficiales-hay','Orientación general','¿Qué becas oficiales hay?','Las becas generales y ayudas NEAE se consultan en el portal oficial de Becas Educación y en la sede del Ministerio. Los plazos cambian por curso.','["becas-portada", "beca-general", "beca-neae"]'::jsonb,13),
('faq-qu-son-las-ayudas-neae','Orientación general','¿Qué son las ayudas NEAE?','Son ayudas para alumnado con necesidad específica de apoyo educativo. Tienen convocatoria, requisitos y plazo propios.','["beca-neae"]'::jsonb,14),
('faq-hay-plazas-reservadas-por-discapacidad','Orientación general','¿Hay plazas reservadas por discapacidad?','Sí, la admisión universitaria contempla reserva para estudiantes con discapacidad conforme a normativa. Debe consultarse la convocatoria y el procedimiento CIUG/universidad.','["rd-412-2014", "ciug-admision"]'::jsonb,15),
('faq-hay-plazas-reservadas-para-deportistas','Orientación general','¿Hay plazas reservadas para deportistas?','Sí, existen reservas para deportistas de alto nivel y alto rendimiento en los términos de la normativa. Debe acreditarse la condición y revisar el procedimiento vigente.','["rd-412-2014", "ciug-admision"]'::jsonb,16),
('faq-dnde-veo-salidas-laborales','Orientación general','¿Dónde veo salidas laborales?','Para una primera aproximación, revisa SEPE por titulaciones y ocupaciones, y cruza esa información con oferta local, prácticas y especialización.','["sepe-titulaciones", "sepe-ocupaciones"]'::jsonb,17),
('faq-qu-pasa-si-busco-electricidad-y-aparecen-varias-opciones','Orientación general','¿Qué pasa si busco electricidad y aparecen varias opciones?','Debes elegir si te refieres a un ciclo de grado medio, un ciclo superior, automatización, mantenimiento electrónico u otra vía. ITINERA mostrará opciones para desambiguar.','["todofp-familias", "xunta-fp-ciclos"]'::jsonb,18),
('faq-qu-diferencia-hay-entre-educacin-infantil-fp-y-grado-en-educacin-infantil','Orientación general','¿Qué diferencia hay entre Educación Infantil FP y Grado en Educación Infantil?','El Técnico Superior en Educación Infantil es FP de grado superior; el Grado en Educación Infantil es un título universitario. Tienen itinerarios y salidas diferentes.','["todofp", "qedu", "ruct"]'::jsonb,19),
('faq-la-herramienta-sustituye-al-orientador-o-a-la-administracin','Orientación general','¿La herramienta sustituye al orientador o a la administración?','No. ITINERA organiza información y orienta la consulta, pero las decisiones deben verificarse en fuentes oficiales y, cuando proceda, con orientación profesional.','["ciug-admision", "todofp", "ruct"]'::jsonb,20),
('faq-qu-son-los-crditos-ects','Orientación general','¿Qué son los créditos ECTS?','Los créditos ECTS miden el volumen de trabajo del estudiante en enseñanzas universitarias oficiales. Un curso completo suele equivaler a 60 ECTS, aunque siempre debe revisarse el plan de estudios oficial del título.','["rd-822-2021", "ruct"]'::jsonb,21),
('faq-cuntos-crditos-tiene-normalmente-un-grado-universitario','Orientación general','¿Cuántos créditos tiene normalmente un grado universitario?','Con carácter general, muchos grados se organizan en 240 ECTS, aunque existen estructuras específicas. La comprobación debe hacerse en el plan de estudios oficial y en RUCT.','["rd-822-2021", "ruct"]'::jsonb,22),
('faq-qu-diferencia-hay-entre-grado-oficial-y-ttulo-propio','Orientación general','¿Qué diferencia hay entre grado oficial y título propio?','El grado oficial aparece en RUCT y tiene validez oficial. Los títulos propios pueden tener interés formativo, pero no sustituyen un título oficial cuando este es requisito académico o profesional.','["ruct", "ruct-faq"]'::jsonb,23),
('faq-qu-es-una-profesin-regulada','Orientación general','¿Qué es una profesión regulada?','Es una profesión cuyo ejercicio exige cumplir requisitos académicos o profesionales establecidos por normativa. En esos casos hay que revisar el grado, el máster habilitante y la normativa aplicable.','["ruct-faq", "rd-822-2021"]'::jsonb,24),
('faq-qu-es-un-mster-habilitante','Orientación general','¿Qué es un máster habilitante?','Es un máster universitario oficial que habilita para ejercer una profesión regulada cuando así lo exige la normativa. No todos los másteres oficiales son habilitantes.','["ruct-faq", "rd-822-2021"]'::jsonb,25),
('faq-arquitectura-requiere-mster-habilitante','Orientación general','¿Arquitectura requiere máster habilitante?','La vía habitual incluye el grado correspondiente en fundamentos de arquitectura o equivalente y el Máster Universitario en Arquitectura. Debe verificarse en RUCT y en la universidad.','["ruct", "ruct-faq", "rd-822-2021"]'::jsonb,26),
('faq-derecho-requiere-mster-para-ejercer','Orientación general','¿Derecho requiere máster para ejercer?','Para ejercer la abogacía y la procura se exige formación habilitante y requisitos profesionales específicos. El Grado en Derecho por sí solo no equivale automáticamente a habilitación profesional completa.','["ruct-faq", "rd-822-2021"]'::jsonb,27),
('faq-psicologa-requiere-mster-habilitante','Orientación general','¿Psicología requiere máster habilitante?','Para ejercer como Psicólogo/a General Sanitario/a se requiere el Máster Universitario en Psicología General Sanitaria. Otras salidas de Psicología pueden tener requisitos distintos.','["ruct-faq", "rd-822-2021"]'::jsonb,28),
('faq-qu-pasa-si-una-materia-pondera-mucho-pero-se-me-da-mal','Orientación general','¿Qué pasa si una materia pondera mucho pero se me da mal?','Conviene comparar ponderación, nota realista y base académica. Una materia con alta ponderación puede no compensar si la calificación esperable es baja. Debe hacerse una simulación prudente con la tabla CIUG.','["ciug-ponderaciones-2026", "ciug-admision"]'::jsonb,29),
('faq-dnde-veo-las-notas-de-corte','Orientación general','¿Dónde veo las notas de corte?','En Galicia deben consultarse en la CIUG. Las notas de corte son referencias de admisiones anteriores, no garantías para cursos futuros.','["ciug-admision", "ciug-notas-corte"]'::jsonb,30),
('faq-puedo-entrar-a-la-universidad-desde-fp-superior','Orientación general','¿Puedo entrar a la universidad desde FP superior?','Sí, la FP de grado superior es una vía de acceso a la universidad. La admisión concreta, mejora de nota y criterios deben comprobarse en la CIUG y en la normativa vigente.','["ciug-admision", "todofp"]'::jsonb,31),
('faq-qu-diferencia-hay-entre-fp-de-grado-medio-y-grado-superior','Orientación general','¿Qué diferencia hay entre FP de grado medio y grado superior?','El grado medio suele ser una vía posterior a ESO y el grado superior una vía de cualificación superior a la que se accede desde Bachillerato, FP u otras vías. Los requisitos se deben revisar oficialmente.','["todofp", "xunta-fp-oferta"]'::jsonb,32),
('faq-dnde-veo-en-qu-centros-de-galicia-se-ofrece-un-ciclo','Orientación general','¿Dónde veo en qué centros de Galicia se ofrece un ciclo?','La fuente adecuada es la oferta oficial de FP de la Xunta y el buscador de centros. Puede cambiar por curso, régimen y plazas.','["xunta-fp-oferta", "xunta-fp-centros"]'::jsonb,33),
('faq-qu-becas-oficiales-existen','Orientación general','¿Qué becas oficiales existen?','Las principales referencias son el portal oficial de Becas Educación, la beca general y las ayudas para alumnado con necesidad específica de apoyo educativo cuando proceda.','["becas-portada", "beca-general", "beca-neae", "becas-educacion-portada"]'::jsonb,34),
('faq-hay-plazas-para-deportistas-de-alto-nivel-o-alto-rendimiento','Orientación general','¿Hay plazas para deportistas de alto nivel o alto rendimiento?','Puede existir reserva de plazas o condiciones específicas para deportistas de alto nivel o alto rendimiento. Deben comprobarse en la normativa de admisión y en la universidad correspondiente.','["rd-412-2014", "boe-rd-534-2024", "ciug-admision"]'::jsonb,35),
('faq-qu-es-la-preinscripcin-universitaria','Orientación general','¿Qué es la preinscripción universitaria?','Es el procedimiento para solicitar plaza en grados universitarios. En Galicia se gestiona dentro del sistema de admisión al SUG y debe seguir calendarios oficiales.','["ciug-admision"]'::jsonb,36),
('faq-qu-es-la-matrcula-universitaria','Orientación general','¿Qué es la matrícula universitaria?','Es la formalización de la plaza y de las asignaturas después de la admisión. Plazos, precios, anulación y cambios dependen de la universidad y normativa vigente.','["ciug-admision", "ruct"]'::jsonb,37),
('faq-qu-es-una-rama-de-conocimiento','Orientación general','¿Qué es una rama de conocimiento?','Es una clasificación académica de los estudios universitarios, útil para comprender afinidades, acceso y organización. Debe revisarse en la información oficial del título.','["rd-822-2021", "ruct"]'::jsonb,38),
('faq-qu-son-las-menciones-en-un-grado','Orientación general','¿Qué son las menciones en un grado?','Son intensificaciones o itinerarios dentro de algunos grados. No todas habilitan profesionalmente por sí solas y deben revisarse en el plan oficial del título.','["ruct", "rd-822-2021"]'::jsonb,39),
('faq-qu-es-una-doble-titulacin','Orientación general','¿Qué es una doble titulación?','Es un itinerario que combina dos títulos o planes. Hay que comprobar si ambos títulos son oficiales, su carga de créditos, duración y requisitos.','["ruct", "qedu"]'::jsonb,40),
('faq-qu-es-un-campus','Orientación general','¿Qué es un campus?','Es la sede o localización donde se imparte un título. Para decisiones reales hay que revisar universidad, campus, plazas y modalidad en la fuente oficial.','["qedu", "ruct"]'::jsonb,41),
('faq-qu-pasa-si-no-s-si-elegir-bachillerato-o-fp','Orientación general','¿Qué pasa si no sé si elegir Bachillerato o FP?','Debe analizarse el estilo de aprendizaje, objetivo final, tolerancia a materias académicas, interés práctico, plazo y posibilidad de continuidad. ITINERA puede simular rutas alternativas.','["educagob-eso", "todofp", "educagob-bach-opciones"]'::jsonb,42),
('faq-se-puede-pasar-de-eso-directamente-a-un-ciclo-superior','Orientación general','¿Se puede pasar de ESO directamente a un ciclo superior?','No por vía ordinaria directa. Desde ESO lo habitual es ir a Bachillerato o a FP de grado medio. Para acceder a un ciclo superior se necesita cumplir requisitos como Bachillerato, FP de grado medio u otros requisitos válidos. Si no se cumplen, puede existir prueba de acceso a grado superior, con edad, estructura y opciones específicas.','["xunta-proba-gs-info-2026", "xunta-proba-gs-xeral", "todofp"]'::jsonb,43),
('faq-qu-prueba-necesito-si-no-tengo-eso-y-quiero-hacer-un-ciclo-medio','Orientación general','¿Qué prueba necesito si no tengo ESO y quiero hacer un ciclo medio?','Debes revisar la prueba de acceso a ciclos de grado medio. En Galicia la prueba se estructura en parte sociolingüística, parte matemática y parte científico-técnica, con posibles exenciones según la convocatoria.','["xunta-proba-gm-info-2026", "xunta-probas"]'::jsonb,44),
('faq-qu-prueba-necesito-para-acceder-a-un-ciclo-superior-sin-bachillerato-ni-grado-medio','Orientación general','¿Qué prueba necesito para acceder a un ciclo superior sin Bachillerato ni grado medio?','Debes revisar la prueba de acceso a ciclos de grado superior. En Galicia tiene parte común y parte específica con opciones A, B o C vinculadas a familias profesionales.','["xunta-proba-gs-info-2026", "xunta-proba-gs-xeral"]'::jsonb,45),
('faq-qu-materias-entran-en-la-prueba-de-acceso-a-grado-superior-en-galicia','Orientación general','¿Qué materias entran en la prueba de acceso a grado superior en Galicia?','La parte común incluye Lingua galega, Lingua castelá y Matemáticas. La parte específica se organiza por opciones: A, B o C. Debe comprobarse siempre la convocatoria vigente.','["xunta-proba-gs-info-2026", "xunta-proba-gs-xeral"]'::jsonb,46),
('faq-qu-materias-entran-en-la-prueba-de-acceso-a-grado-medio-en-galicia','Orientación general','¿Qué materias entran en la prueba de acceso a grado medio en Galicia?','La prueba se organiza en parte sociolingüística, parte matemática y parte científico-técnica. Incluye Lingua galega, Lingua castelá, Ciencias sociais, Matemáticas, Ciencias da natureza y Tecnoloxía.','["xunta-proba-gm-info-2026"]'::jsonb,47),
('faq-dnde-encuentro-exmenes-anteriores-de-las-pruebas-de-acceso','Orientación general','¿Dónde encuentro exámenes anteriores de las pruebas de acceso?','La Xunta publica exámenes por convocatorias en la sección de pruebas de FP. Conviene usar modelos recientes porque la normativa puede cambiar.','["xunta-exames-probas"]'::jsonb,48),
('faq-es-lo-mismo-una-doble-titulacin-que-una-titulacin-combinada','Orientación general','¿Es lo mismo una doble titulación que una titulación combinada?','No conviene asumir que significan exactamente lo mismo. En la práctica, ambas expresiones pueden usarse para itinerarios que permiten cursar dos planes o una combinación de estudios, pero lo importante es comprobar en la universidad si se obtienen uno o dos títulos oficiales, cuántos créditos ECTS tiene el itinerario, duración, centro responsable, plazas, precio y si ambos títulos figuran como oficiales en RUCT. La denominación comercial de la web universitaria no basta para tomar la decisión.','["ruct", "qedu", "rd-822-2021"]'::jsonb,49),
('faq-puedo-convalidar-mdulos-entre-ciclos-de-fp','Orientación general','¿Puedo convalidar módulos entre ciclos de FP?','Puede ser posible convalidar determinados módulos de Formación Profesional si se cumplen los requisitos normativos. No es automático: depende de los módulos, estudios aportados, currículo y órgano competente. La solicitud debe revisarse en el centro y en el procedimiento oficial.','["mefp-convalidaciones-fp", "mefp-convalidacion-modulos-fp"]'::jsonb,50),
('faq-puedo-reconocer-crditos-de-un-ciclo-superior-en-un-grado-universitario','Orientación general','¿Puedo reconocer créditos de un ciclo superior en un grado universitario?','Puede existir reconocimiento de créditos entre un ciclo de grado superior y un grado universitario, pero depende del ciclo, del grado, de la universidad y de la normativa aplicable. Debe solicitarse a la universidad y comprobarse antes de decidir.','["boe-rd-822-reconocimiento-creditos", "ruct", "qedu"]'::jsonb,51),
('faq-puedo-reconocer-crditos-si-cambio-de-grado-universitario','Orientación general','¿Puedo reconocer créditos si cambio de grado universitario?','Sí puede existir reconocimiento de créditos por estudios universitarios oficiales previos, pero lo resuelve la universidad. Deben revisarse asignaturas, competencias, créditos ECTS y normativa interna.','["boe-rd-822-reconocimiento-creditos", "ruct"]'::jsonb,52),
('faq-criminologa-es-un-grado-universitario-oficial','Orientación general','¿Criminología es un grado universitario oficial?','Puede existir oferta oficial de Grado en Criminología, pero debe comprobarse siempre en RUCT y QEDU para saber universidad, centro, modalidad, oficialidad y plazas. En Galicia también conviene revisar CIUG si se accede al SUG.','["qedu", "ruct", "ciug-admision"]'::jsonb,53)
insert into public.itinera_access_exams(id,title,short,when_needed,age,structure,notes,sources) values
('proba-grao-medio-galicia','Proba de acceso a ciclos formativos de grao medio','Permite acceder a ciclos de grado medio cuando no se posee el requisito académico ordinario.','Cuando la persona no tiene título de ESO, título profesional básico u otro requisito equivalente para acceder a un ciclo de grado medio.','Debe revisarse la convocatoria vigente. En Galicia, la documentación oficial de 2026 recoge requisitos, exenciones y procedimiento de inscripción.','["Parte sociolingüística: Lingua galega, Lingua castelá y Ciencias sociais.", "Parte matemática: Matemáticas.", "Parte científico-técnica: Ciencias da natureza y Tecnoloxía."]'::jsonb,'["La certificación de superación da acceso a cualquier ciclo formativo de grado medio en las condiciones de admisión que se establezcan.", "En Galicia se conserva durante un máximo de dos años la calificación de las partes superadas con puntuación igual o superior a 5, según la información oficial de 2026.", "Pueden existir exenciones; deben revisarse en la convocatoria vigente."]'::jsonb,'["xunta-proba-gm-info-2026", "xunta-probas", "xunta-exames-probas"]'::jsonb),
('proba-grao-superior-galicia','Proba de acceso a ciclos formativos de grao superior','Permite acceder a ciclos de grado superior cuando no se cumple un requisito académico ordinario.','Cuando la persona no tiene Bachillerato, FP de grado medio u otro requisito válido para acceder a un ciclo superior.','En la información general de Xunta para grado superior consta que es necesario tener 19 años o cumplirlos en el año natural de celebración de la prueba.','["Parte común: Lingua galega, Lingua castelá y Matemáticas.", "Parte específica: opción A, B o C según familias profesionales.", "Opción A: Economía da empresa, Lingua estranxeira y Filosofía.", "Opción B: Debuxo técnico, Tecnoloxía industrial y Física.", "Opción C: Ciencias da terra e ambientais, Química y Bioloxía."]'::jsonb,'["La certificación de superación incluye la relación de familias profesionales a las que se podrá acceder, según condiciones de admisión.", "Si se realiza en Galicia y no se supera completa, pueden conservarse partes superadas con puntuación igual o superior a 5 durante los dos años siguientes, según la información general.", "La opción específica debe elegirse con mucho cuidado porque condiciona familias profesionales."]'::jsonb,'["xunta-proba-gs-info-2026", "xunta-proba-gs-xeral", "xunta-probas", "xunta-exames-probas"]'::jsonb)
insert into public.itinera_scholarships(id,title,summary,period,sources) values
('beca-general','Beca general para estudios postobligatorios y universitarios','Beca estatal para Bachillerato, FP, enseñanzas artísticas, deportivas, idiomas, grado y máster, según requisitos generales, económicos y académicos.','Curso 2026/2027: solicitud indicada oficialmente entre abril y mayo de 2026 en el portal de Becas Educación; comprobar siempre el estado vigente.','["becas-portada", "beca-general", "faq-becas"]'::jsonb),
('beca-neae','Ayudas para alumnado con necesidad específica de apoyo educativo','Ayudas dirigidas a alumnado con necesidad específica de apoyo educativo, con convocatoria y requisitos propios.','Curso 2026/2027: plazo oficial indicado del 19 de mayo de 2026 al 10 de septiembre de 2026 en la sede del Ministerio.','["beca-neae", "becas-portada"]'::jsonb)
insert into public.itinera_reservations(id,title,summary,sources) values
('reservation-1','Reserva por discapacidad','En admisión universitaria existe reserva de plazas para estudiantes que acrediten discapacidad en los términos previstos en la normativa. Como criterio estatal general, la norma contempla cupo mínimo para este colectivo; en admisión real debe revisarse CIUG/universidad.','["rd-412-2014", "ciug-admision"]'::jsonb),
('reservation-2','Deportistas de alto nivel y alto rendimiento','La normativa estatal contempla reserva de plazas para deportistas de alto nivel y alto rendimiento y reglas específicas en determinados estudios. Deben acreditarse requisitos y consultar admisión vigente.','["rd-412-2014", "ciug-admision"]'::jsonb),
('reservation-3','Mayores de 25, 40 y 45 años','Existen vías de acceso específicas a la universidad para mayores de 25, 40 y 45 años, con pruebas o procedimientos propios según el caso.','["rd-412-2014", "ciug-admision"]'::jsonb),
('reservation-4','Titulados universitarios o equivalentes','La admisión universitaria contempla cupos y procedimientos para personas con titulación universitaria previa o equivalente.','["rd-412-2014", "ciug-admision"]'::jsonb),
('reservation-5','Cupo general y otros cupos de admisión','La admisión puede organizarse con cupo general y cupos específicos. La distribución exacta y requisitos deben comprobarse en normativa y convocatoria vigente.','["rd-412-2014", "boe-rd-534-2024", "ciug-admision"]'::jsonb)
insert into public.itinera_convalidations(id,title,summary,details,sources) values
('fp-convalidaciones','Convalidación de módulos de Formación Profesional','Permite reconocer formación ya superada para no volver a cursar determinados módulos, siempre que la normativa y el órgano competente lo permitan.','["La solicitud suele tramitarse desde el centro educativo, no directamente por libre ante el Ministerio cuando corresponde resolución ministerial.", "La resolución depende de módulos concretos, estudios aportados, currículo y normativa vigente.", "No debe prometerse convalidación automática sin revisar el caso individual y la convocatoria/procedimiento."]'::jsonb,'["mefp-convalidaciones-fp", "mefp-convalidacion-modulos-fp"]'::jsonb),
('universidad-reconocimiento-creditos','Reconocimiento y transferencia de créditos universitarios','Las universidades pueden reconocer créditos por estudios universitarios oficiales previos, enseñanzas superiores, experiencia profesional o determinados estudios, según normativa y regulación interna.','["Debe comprobarse en el plan de estudios, normativa de la universidad y procedimiento de reconocimiento.", "El reconocimiento no es idéntico a una convalidación automática: requiere solicitud y resolución.", "Entre FP superior y grado universitario puede haber reconocimiento en algunos casos, pero depende del grado, ciclo, universidad y normativa aplicable."]'::jsonb,'["boe-rd-822-reconocimiento-creditos", "ruct", "qedu"]'::jsonb),
('entre-grados','Cambio de grado, doble titulación y reconocimiento','Al cambiar de grado o cursar dobles titulaciones puede existir reconocimiento de créditos si hay equivalencia suficiente, pero lo decide la universidad.','["Hay que distinguir doble titulación, titulación combinada, itinerario simultáneo y reconocimiento posterior.", "La denominación comercial no basta: comprueba títulos oficiales en RUCT, créditos ECTS y normativa de la universidad.", "El alumnado debe pedir estudio individualizado a la universidad antes de tomar una decisión costosa."]'::jsonb,'["boe-rd-822-reconocimiento-creditos", "ruct", "qedu"]'::jsonb)
